protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents and direct SQL queries reference "Discriminator".
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer prepends the discriminator to id values.
        // Existing documents use the "Product|123" format written by EF Core 8.
        entity.HasRootDiscriminatorInJsonId(true);

        // EF Core 9 Cosmos provider throws on HasIndex — indexing is managed
        // via the container's indexing policy (Azure Portal / Bicep / Terraform).
        // Removed: entity.HasIndex(p => p.Sku);
    });
}

